// Package sample provides utilities for data processing.
package sample

import (
	"fmt"
	"strings"
)

// DataProcessor handles data transformation operations.
type DataProcessor struct {
	Name  string
	cache map[string]string
}

// NewDataProcessor creates a new DataProcessor instance.
func NewDataProcessor(name string) *DataProcessor {
	return &DataProcessor{
		Name:  name,
		cache: make(map[string]string),
	}
}

// Process transforms a slice of strings.
func (dp *DataProcessor) Process(data []string) []string {
	result := make([]string, len(data))
	for i, item := range data {
		result[i] = dp.transform(item)
	}
	return result
}

// transform converts a single item.
func (dp *DataProcessor) transform(item string) string {
	if cached, ok := dp.cache[item]; ok {
		return cached
	}
	result := strings.ToUpper(strings.TrimSpace(item))
	dp.cache[item] = result
	return result
}

// StandaloneFunc is a package-level function.
func StandaloneFunc(x, y int) int {
	helper := func(val int) int {
		return val * 2
	}
	return helper(x) + helper(y)
}

